INSERT INTO `faq` (`id`, `question`, `answer`, `sort_order`, `status`) VALUES
(1, 'Как понять, что мне пора к психологу?', 'Если вы чувствуете, что не справляетесь с эмоциями, постоянно испытываете тревогу, усталость, проблемы со сном или сложности в отношениях, которые повторяются раз за разом — это веский повод обратиться к специалисту.', 1, 'published'),
(2, 'Гарантируете ли вы конфиденциальность?', 'Абсолютно. Соблюдение профессиональной этики и полная анонимность — наш главный приоритет. Вся информация, обсуждаемая на сессиях, остается строго между вами и вашим терапевтом.', 2, 'published'),
(3, 'Как выбрать \"своего\" специалиста?', 'На странице \"Специалисты\" вы можете ознакомиться с биографиями наших психологов. Выбирайте того, кто откликается вам визуально и чьи методы работы подходят под ваш запрос.', 3, 'published');

