INSERT INTO `specialists` (`id`, `user_id`, `photo`, `first_name`, `patronymic`, `last_name`, `specialization`, `experience_years`, `education`, `description`, `work_schedule`, `directions`, `block1_title`, `block1_text`, `block2_title`, `block2_text`) VALUES
(1, 7, 'img/анна.png', 'Анна', 'Богдановна', 'Малявская', 'Детский и подростковый психолог, семейный консультант, арт-терапевт', 3, 'Белорусский государственный педагогический университет им. М. Танка (БГПУ), Институт психологии, специальность «Психология семейных отношений». Семинары по арт-терапии и работе с пластическими материалами (глина, песок) в детском консультировании.', '«Ребенок — это не пластилин, из которого нужно вылепить удобного взрослого, и не испорченный механизм, требующий срочного ремонта. Ребенок — это целая вселенная, которая говорит на своем особенном языке: языке игры, метафор, рисунков и порой ”трудного” поведения.\r\nВ своей работе с детьми и подростками я использую интегративный подход, бережно сочетая игровую терапию, арт-терапию и основы семейного консультирования. Симптомы ребенка (будь то внезапная агрессия, капризы, страх темноты или школьная неуспеваемость) — это почти всегда его единственный способ прокричать взрослым о том, что внутри него накопилось слишком много напряжения, с которым его незрелая психика не справляется.\r\nЯ никогда не работаю с ребенком в отрыве от его семьи. Мой подход строится на глубоком сотрудничестве с родителями. Я не учу вас жить и не раздаю банальных советов. Моя задача — помочь вам расшифровать сигналы вашего ребенка, понять причины его поведения и дать вам практические, бережные инструменты для восстановления мира, тепла и авторитета в вашем доме».', 'Пн, Вт, Чт 09:00 - 15:00', 'Семейные конфликты, Проблемы в отношениях, Развод, Измена, Созависимость, Одиночество, Семья', '', '', '', ''),
(3, 9, 'img/Generated Image April 28, 2026 - 1_06AM.png', 'Софья', 'Михайловна', 'Богушевич', 'Психолог, специалист по работе со стрессом, эмоциональной саморегуляцией и самооценкой', 1, 'Белорусский государственный университет (БГУ), факультет философии и социальных наук, специальность «Социальная психология».', '«Здравствуйте. Если вы сейчас читаете этот текст, возможно, внутри вас скопилось много усталости, хаоса или тревоги. Сделать первый шаг к психологу бывает очень страшно. Кажется, что нужно обязательно прийти с какой-то огромной, \"правильно сформулированной\" проблемой, или что вас обязательно начнут оценивать.\r\nЯ хочу сразу сказать вам: со мной можно быть любым. Можно молчать, если не находятся слова. Можно плакать, если больно. Можно злиться на весь мир. Мой кабинет и онлайн-пространство — это безопасная, теплая гавань, где вас просто выслушают, поймут и поддержат.\r\nЯ — начинающий специалист, и я считаю это своей огромной ценностью. Во мне нет профессионального цинизма или выгорания. У меня свежий взгляд на психологические методы, искренний интерес к каждому человеку и бережное желание помочь вам справиться с тем стрессом, который мешает радоваться жизни. Мы будем двигаться в вашем индивидуальном темпе, бережно распутывая узелки тревоги и возвращая вам устойчивость, спокойствие и контакт со своими настоящими чувствами».', 'Пн, Вт, Ср, Чт, Пт 09:00 - 15:00', 'Стресс, Тревожность, Самооценка, Эмоции, Саморегуляция, Молодые специалисты, КПТ', 'В каких состояниях я буду вашей бережной опорой?', 'Когда вы в постоянном стрессе: учеба, сессия, новая работа, переезд, или просто накопившаяся фоновая усталость от бесконечных дел. Мы научимся простым и действенным техникам саморегуляции.\r\n\r\nКогда тревога мешает дышать: если вас часто накрывают беспокойные мысли о будущем, страх сделать ошибку или неуверенность в завтрашнем дне.\r\n\r\nКогда вы потеряли контакт со своими желаниями: если вы привыкли заботиться обо всех вокруг, а на вопрос ”Чего хочу я сам?” внутри возникает только звенящая пустота.\r\n\r\nКогда трудно принять и полюбить себя: мы будем бережно работать с самооценкой, учиться сочувствовать себе в сложные моменты и замечать свои маленькие победы без вечной критики.', 'Почему не стоит бояться моей молодой практики?', '«Я знаю, что некоторые клиенты с опаской относятся к молодым психологам, и это нормальные сомнения. Но за моей спиной стоит мощная поддержка всей команды центра J.O.Y.\r\nЯ регулярно прохожу личную психотерапию и еженедельно разбираю свои клиентские кейсы на супервизиях с опытнейшими старшими коллегами центра (конечно, с полным сохранением вашей анонимности). Это гарантирует, что в нашей работе используются только безопасные, современные и проверенные методы. Я вкладываю максимум своего внимания и тепла в каждую встречу, чтобы вы почувствовали: вы больше не один на один со своими трудностями».'),
(5, 15, 'img/nastya.png', 'Анастасия', 'Сергеевна', 'Жодевская', 'Семейный психолог, сертифицированный системный семейный терапевт, гештальт-терапевт', 2, 'Белорусский государственный университет (БГУ), факультет философии и социальных наук, специальность «Психология».', '«Большинство наших душевных ран рождается в отношениях с близкими людьми, но именно в отношениях — только уже в терапевтических, безопасных и бережных — эти раны могут быть исцелены.\r\nВ своей практике я совмещаю два глубоких направления: гештальт-терапию и системную семейную психотерапию. Это позволяет мне видеть человека не изолированно, а как часть сложной системы его связей — семейных сценариев, детско-родительских паттернов и супружеских динамик. Ко мне приходят, когда кажется, что близкие люди говорят на разных языках, когда за теплой близостью скрывается страх быть отвергнутым, а вместо диалога раз за разом вспыхивает привычная ссора.\r\nНа моих сессиях нет места суду, оценкам или поиску ”виноватого”. Я создаю пространство, в котором вы сможете замедлиться, перевести дух и бережно исследовать то, как вы организуете контакт с собой и партнером. Мы будем учиться обнаруживать ваши истинные потребности, которые часто прячутся за гневом, обидой или глухим молчанием. Терапия со мной — это путь от автоматических защитных реакций к осознанному, теплому и живому диалогу, где вас наконец-то слышат, а вы получаете возможность услышать другого без необходимости защищаться».', 'Пн, Ср, Пт 10:00-17:00', 'Семейные конфликты, Проблемы в отношениях, Развод, Измена, Созависимость, Одиночество, Семья', 'С какими темами я работаю наиболее часто', 'Кризисы и тупики в супружеских отношениях: когда кажется, что любовь прошла, осталась только усталость, а общение превратилось в обмен бытовыми претензиями или затяжное молчание.\r\n\r\nПроживание семейных травм: помощь парам в преодолении последствий измены, предательства, эмоциональной холодности или затяжного кризиса доверия. Нахождение точек опоры для восстановления союза или принятия решения о завершении отношений.\r\n\r\nБережный развод и расставание: сопровождение пар в процессе цивилизованного прекращения отношений. Помощь в снижении уровня боли, экологичном завершении эмоциональной связи и выстраивании новых родительских (но уже не супружеских) ролей ради психологического здоровья детей.\r\n\r\nЭмоциональная зависимость и созависимость: работа с клиентами, которые склонны ”растворяться” в партнере, теряя собственные границы, интересы, цели и ощущение личной самоценности. Возвращение чувствительности к собственной жизни.', 'Мой профессиональный принцип в работе с парами', '«Мой главный терапевтический ориентир — это бережность, безопасность и терапевтический нейтралитет. Приходя ко мне на парную сессию, вы можете быть уверены, что я не приму чью-либо сторону. Для меня клиент — это сама пара, те невидимые нити, которые связывают вас двоих.\r\n\r\nЯ бережно храню тайну всего, что звучит в моем кабинете, и создаю условия, при которых даже самые болезненные темы могут быть высказаны безопасно для обоих партнеров. Моя задача — не переделать вас под общепринятые шаблоны ”идеальной семьи”, а помочь вам обнаружить вашу собственную формулу счастливых, поддерживающих и свободных отношений».'),
(6, 16, 'img/полина.png', 'Полина', 'Дмитриевна', 'Будевич', 'Основатель центра, психолог-консультант, сертифицированный бизнес-коуч ICF, специалист по работе с выгоранием и самооценкой', 2, 'Белорусский государственный университет (БГУ), факультет философии и социальных наук, специальность «Социальная психология». Авторский курс по психотерапии эмоционального выгорания.', '«Давайте сразу к делу. Если вы годами работаете по 12 часов в сутки, но внутри всё равно чувствуете себя самозванцем; если ваш внутренний критик звучит громче, чем любые похвалы руководства; если вы уперлись в финансовый потолок и прокрастинируете вместо важных шагов — вы пришли по адресу.\r\nЯ не верю в абстрактные разговоры ”обо всём и ни о чём”. Мой подход — это сплав практической психологии самооценки и классического сертифицированного коучинга по стандартам ICF. На сессиях мы работаем на стыке двух плоскостей:\r\n1. Глубинная психология: находим и убираем те деструктивные установки (”я недостаточно хорош”, ”выделяться опасно”, ”ошибаться нельзя”), которые блокируют ваше движение.\r\n2. Коучинговые технологии: строим четкие, измеримые цели, учимся планировать без насилия над собой, тестируем новые поведенческие гипотезы и нарабатываем реальные навыки продвижения в карьере или бизнесе.\r\nСо мной не нужно быть идеальным. Со мной можно быть уставшим, запутавшимся или амбициозным. Мы не будем годами копаться в вашем детстве, если ваш запрос — масштабирование бизнеса или выход из жесткого профессионального выгорания. Мы возьмем ваше настоящее и бережно, но твердо перенаправим его в желаемое будущее».', 'Вт, Ср, Чт 10:00 - 18:00', 'Выгорание, Самооценка, Карьера, Бизнес-коучинг, Прокрастинация, Личные границы, Коуч', 'Кому точно ко мне?', 'Выгорели дотла: просыпаетесь уже уставшими, работа не приносит радости, а мысли о понедельнике вызывают глухую тоску. Мы вернем ресурс и перестроим баланс ”работа/жизнь”.\r\n\r\nСиндром самозванца мешает росту: вы списываете все свои успехи на ”просто повезло” и боитесь просить о повышении или повышать стоимость своих услуг.\r\n\r\nПроблемы с личными границами: соглашаетесь на сверхурочную работу, не умеете говорить ”нет” коллегам и клиентам, а потом тихо злитесь на себя и весь мир.\r\n\r\nКарьерный тупик: хотите сменить сферу деятельности, запустить свой проект или выйти на новый доход, но дикий страх неизвестности парализует любые действия.', 'Мой формат работы', '«Мы работаем по четкой, понятной вам структуре. Каждая сессия — это конкретный фокус, разбор ваших реальных кейсов за неделю и планирование практических шагов.\r\nЯ не буду давать вам готовых советов — я помогу вам выстроить вашу личную внутреннюю опору, чтобы вы сами видели свои решения. Между встречами вы будете выполнять небольшие практические задания в комфортном для вас темпе. Это терапия действия, где изменения вы начинаете замечать не в теории, а в своей реальной жизни, кошельке и графике».'),
(7, 17, 'img/евгеша.png', 'Евгений', 'Анатолиевич', 'Карчанов', 'Клинический психолог, когнитивно-поведенческий терапевт (КПТ)', 2, 'Белорусский государственный педагогический университет им. М. Танка (БГПУ), Институт психологии, специальность «Практическая психология».', '«Психотерапия — это не просто душевный разговор, это строго научный процесс исследования мышления, поведения и работы вашей нервной системы.\r\nВ своей практике я опираюсь на методы когнитивно-поведенческой терапии (КПТ) — направление с доказанной эффективностью, рекомендованное Всемирной организацией здравоохранения. Наш мозг устроен удивительным образом: нас ранят не сами события, происходящие в жизни, а то, как мы их интерпретируем. Автоматические мысли, глубинные убеждения о себе и мире, выученные паттерны поведения — все это создает ментальные фильтры, через которые мы раз за разом испытываем панику, тревогу, бессилие или апатию.\r\nКак клинический психолог, я понимаю физиологию стресса и тревожных расстройств изнутри. Наша совместная работа будет структурированной, понятной и ориентированной на результат. Мы не просто будем анализировать ваше прошлое, мы станем исследовать ваше настоящее: разбирать механизмы панических атак, отслеживать искажения в мышлении и проводить поведенческие эксперименты. На моих сессиях много ясности, логики, наглядных схем и практических домашних заданий, которые помогут вам вернуть управление своей жизнью в собственные руки».', 'Вт, Чт 12:00 - 21:00, Сб 11:00 - 16:00', '', '', '', '', '');

